const WRAPPER_URL = 'http://10.1.1.105:3001';
const DEFAULT_MODEL = 'sonnet';
const DEFAULT_MAX_TOKENS = 4000;

const SYSTEM_PROMPTS = {
  'collect-diagnostics': `Du bist ein erfahrener Linux/Netzwerk-Administrator.
Du hast SSH-Zugang zu einem Server und sollst Diagnose-Daten für ein spezifisches Problem sammeln.

REGELN:
- Passe deine Befehle an die Plattform an (Debian, Ubuntu, RouterOS, OPNsense, OpenWrt etc.)
- Sammle NUR relevante Daten — kein Shotgun-Debugging
- Gib die Befehle UND deren Output strukturiert zurück
- Fasse am Ende kurz zusammen was du siehst (Auffälligkeiten)
- Führe KEINE Änderungen durch — nur lesen/diagnostizieren

OUTPUT-FORMAT (JSON):
{"commands_executed": [{"command": "...", "output": "...", "exit_code": 0}], "summary": "Kurze Zusammenfassung", "platform_detected": "debian-12|..."}`,

  'root-cause-analysis': `Du bist ein erfahrener Incident-Response-Analyst.
Bestimme die URSACHE (nicht nur Symptom) aus den Diagnose-Daten.

REGELN:
- Unterscheide Symptom und Ursache
- Nenne Konfidenz (high/medium/low) mit Begründung
- Sei präzise — keine vagen Vermutungen

OUTPUT-FORMAT (JSON):
{"symptom": "...", "root_cause": "...", "confidence": "high|medium|low", "reasoning": "...", "alternative_causes": [], "affected_service": "...", "category": "disk|cpu|memory|service|network|certificate|backup|other"}`,

  'generate-remediation': `Du bist ein erfahrener System-Administrator.
Erstelle eine Schritt-für-Schritt-Anleitung zur Behebung.

REGELN:
- Jeder Schritt = ein konkreter Befehl
- Passe Befehle an die Plattform an
- Bewerte Risiko jedes Schritts
- Bei kritischen Systemen: konservativer
- Maximal 10 Schritte

OUTPUT-FORMAT (JSON):
{"steps": [{"nr": 1, "description": "...", "command": "...", "risk": "none|low|medium|high", "auto_approve": true, "rollback": null, "expected_result": "..."}], "overall_risk": "low|medium|high", "auto_approve_all": true, "estimated_duration_seconds": 60, "long_term_recommendations": []}`,

  'execute-remediation': `Du bist ein System-Administrator mit SSH-Zugang.
Führe die vorgegebenen Schritte EXAKT aus und protokolliere jeden.

REGELN:
- Schritte in Reihenfolge ausführen
- Bei Fehler (exit_code != 0): SOFORT stoppen
- JEDEN Schritt protokollieren
- NUR vorgegebene Befehle — keine Eigeninitiative

OUTPUT-FORMAT (JSON):
{"steps_executed": [{"nr": 1, "command": "...", "output": "...", "exit_code": 0, "modified": false, "modification_reason": null}], "completed": true, "stopped_at_step": null, "stop_reason": null}`,

  'evaluate-result': `Du bist ein Incident-Response-Analyst.
Vergleiche Zustand VOR und NACH der Remediation.

REGELN:
- Relevante Metriken vergleichen
- Prüfe ob ursprüngliches Problem behoben
- Prüfe ob neue Probleme entstanden
- Bewerte: RESOLVED, UNRESOLVED oder DEGRADED

OUTPUT-FORMAT (JSON):
{"status": "RESOLVED|UNRESOLVED|DEGRADED", "comparison": {"metric": "...", "before": "...", "after": "...", "target": "...", "target_met": true}, "new_issues": [], "explanation": "...", "next_steps": null, "close_ticket": true}`,

  'generic': `Du bist ein erfahrener System-Administrator und Analyst.
Beantworte die Anfrage präzise und strukturiert.
Wenn ein bestimmtes Output-Format angegeben ist, halte dich daran.`
};

function buildUserPrompt(phase, data) {
  switch (phase) {
    case 'collect-diagnostics':
      return `AUFGABE: SSH-Diagnose sammeln.\n\nHOST:\n- Hostname: ${data.hostname}\n- IP: ${data.ip}\n- Platform: ${data.platform || 'unbekannt'}\n- SSH-User: ${data.ssh_user}\n- SSH-Passwort: ${data.ssh_password || 'Key-Auth'}\n${data.ssh_key_file ? '- SSH-Key: ' + data.ssh_key_file : ''}\n\nPROBLEM:\n- Symptom: ${data.symptom}\n- Severity: ${data.severity || 'unbekannt'}\n- Seit: ${data.event_time || 'unbekannt'}\n${data.trigger_description ? '- Details: ' + data.trigger_description : ''}\n\nSammle relevante Diagnose-Daten.`;
    case 'root-cause-analysis':
      return `SYMPTOM: ${data.symptom}\nHOST: ${data.hostname} (${data.platform || 'unbekannt'})\n\nDIAGNOSE-DATEN:\n${JSON.stringify(data.diagnostics, null, 2)}\n${data.zabbix_history ? '\nZABBIX-HISTORY:\n' + JSON.stringify(data.zabbix_history, null, 2) : ''}\n\nBestimme die ROOT CAUSE.`;
    case 'generate-remediation':
      return `ROOT CAUSE:\n${JSON.stringify(data.rca, null, 2)}\n\nHOST: ${data.hostname} (${data.platform || 'unbekannt'})\nKritisch: ${data.critical ? 'JA' : 'Nein'}\nWartungsfenster: ${data.maintenance_window || 'keins'}\n\nErstelle Behebungsschritte.`;
    case 'execute-remediation':
      return `HOST:\n- IP: ${data.ip}\n- SSH-User: ${data.ssh_user}\n- SSH-Passwort: ${data.ssh_password || 'Key-Auth'}\n${data.ssh_key_file ? '- SSH-Key: ' + data.ssh_key_file : ''}\n\nSCHRITTE:\n${JSON.stringify(data.steps, null, 2)}\n\nAusführen. Bei Fehler: STOPPEN.`;
    case 'evaluate-result':
      return `PROBLEM: ${data.symptom} auf ${data.hostname}\n\nVORHER:\n${JSON.stringify(data.before, null, 2)}\n\nNACHHER:\n${JSON.stringify(data.after, null, 2)}\n\nDURCHGEFÜHRT:\n${JSON.stringify(data.steps_executed, null, 2)}\n\nBewerte: Gelöst?`;
    case 'generic':
      return data.prompt || JSON.stringify(data);
    default:
      return JSON.stringify(data);
  }
}

const input = $input.first().json;
const phase = input.phase || 'generic';
const data = input.data || input;
const systemPrompt = SYSTEM_PROMPTS[phase] || SYSTEM_PROMPTS['generic'];
const userPrompt = buildUserPrompt(phase, data);
const temp = (phase === 'execute-remediation') ? 0.1 : 0.3;

return [{ json: {
  wrapper_url: WRAPPER_URL,
  payload: {
    model: input.model || DEFAULT_MODEL,
    messages: [
      { role: 'system', content: systemPrompt },
      { role: 'user', content: userPrompt }
    ],
    max_tokens: input.max_tokens || DEFAULT_MAX_TOKENS,
    temperature: input.temperature || temp,
    output_format: 'json'
  }
}}];

const response = $input.first().json;
const phase = $('Prompt Builder').first().json.phase;

let parsed;
try {
  const content = response.choices[0].message.content;
  parsed = typeof content === 'string' ? JSON.parse(content) : content;
} catch (e) {
  parsed = {
    raw: response.choices?.[0]?.message?.content || 'No content',
    parse_error: true,
    error_message: e.message
  };
}

return [{ json: {
  phase: phase,
  result: parsed,
  model: response.model,
  tokens: response.usage,
  parse_error: parsed.parse_error || false
}}];

